evaluators.evaluation_logic:
const checkpoints = [];

const viewStates = JSON.parse(localStorage.getItem('branch_search_view_states') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const banks = JSON.parse(localStorage.getItem('banks') || '[]');
const rvBranches = JSON.parse(localStorage.getItem('recently_viewed_branches') || '[]');
let clipboard = null;
try { clipboard = JSON.parse(localStorage.getItem('__clipboard__') || 'null'); } catch (e) { clipboard = null; }

// Build bank lookup
const bankById = {};
banks.forEach(b => { if (b && b.id) bankById[b.id] = b; });

// Candidate branches: Emirates NBD, conventional bank, Bur Dubai, Dubai, retail banking, with a primary SWIFT code
const candidateBranches = branches.filter(br => {
  if (!br || br.area !== 'Bur Dubai' || br.city !== 'Dubai') return false;
  const bank = bankById[br.bank_id];
  if (!bank || bank.name !== 'Emirates NBD' || bank.bank_type !== 'conventional') return false;
  const hasRetail = !!br.has_retail_banking || (Array.isArray(br.service_types) && br.service_types.includes('retail_banking'));
  if (!hasRetail) return false;
  return typeof br.swift_primary_code === 'string' && br.swift_primary_code.length > 0;
});

// CP1 (0.35): Bank & Branch Search filtered to Emirates NBD retail branches in Bur Dubai, Dubai
const bankSearchState = viewStates.find(vs => vs && vs.mode === 'bank_search');
const cp1Passed = !!bankSearchState &&
  bankSearchState.city_filter === 'Dubai' &&
  bankSearchState.area_filter === 'Bur Dubai' &&
  bankSearchState.bank_name_filter === 'Emirates NBD' &&
  Array.isArray(bankSearchState.service_type_filters) &&
  bankSearchState.service_type_filters.includes('retail_banking');
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// CP2 (0.30): User opened at least one qualifying Emirates NBD Bur Dubai retail branch
const openedCandidateIds = rvBranches.filter(id => candidateBranches.some(br => br.id === id));
checkpoints.push({ passed: openedCandidateIds.length >= 1, weight: 0.30 });

// CP3 (0.35): Clipboard holds the primary SWIFT code of an opened qualifying branch
let cp3Passed = false;
if (clipboard && clipboard.value && openedCandidateIds.length > 0) {
  cp3Passed = candidateBranches.some(br =>
    openedCandidateIds.includes(br.id) && br.swift_primary_code === clipboard.value
  );
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

let feeParams = null;
try { feeParams = JSON.parse(localStorage.getItem('task2_feeComparisonParams') || 'null'); } catch (e) { feeParams = null; }
const lastSavedBranchId = localStorage.getItem('task2_lastSavedBranchId') || null;
const feeSchedules = JSON.parse(localStorage.getItem('branch_fee_schedules') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const banks = JSON.parse(localStorage.getItem('banks') || '[]');
const savedBranches = JSON.parse(localStorage.getItem('saved_branches') || '[]');

const dibBank = banks.find(b => b && b.name === 'Dubai Islamic Bank');
const dibBankId = dibBank ? dibBank.id : null;
const maxCap = 20;

// CP1 (0.35): Fee comparison filters set to Dubai Islamic Bank, outgoing international transfer, AED, cap <= 20, sorted by fee_amount_asc
const cp1Passed = !!feeParams && dibBankId &&
  feeParams.bankId === dibBankId &&
  feeParams.feeType === 'outgoing_international_transfer' &&
  feeParams.currencyCode === 'AED' &&
  typeof feeParams.maxFeeAmount === 'number' && feeParams.maxFeeAmount <= maxCap &&
  feeParams.sortBy === 'fee_amount_asc';
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// Build branch lookup
const branchById = {};
branches.forEach(br => { if (br && br.id) branchById[br.id] = br; });

// Qualifying Dubai Islamic Bank schedules: outgoing international, AED, amount <= 20
const qualifyingSchedules = feeSchedules.filter(fs => {
  if (!fs || fs.fee_type !== 'outgoing_international_transfer' || fs.currency_code !== 'AED') return false;
  if (typeof fs.amount !== 'number' || fs.amount > maxCap) return false;
  const br = branchById[fs.branch_id];
  if (!br || !dibBankId) return false;
  return br.bank_id === dibBankId;
});

const cheapestAmount = qualifyingSchedules.length
  ? Math.min(...qualifyingSchedules.map(fs => fs.amount))
  : null;

const qualifyingBranchIds = Array.from(new Set(qualifyingSchedules.map(fs => fs.branch_id)));

// CP2 (0.30): User saved a qualifying Dubai Islamic Bank branch that is within the 20 AED cap
const savedQualifying = lastSavedBranchId &&
  qualifyingBranchIds.includes(lastSavedBranchId) &&
  savedBranches.some(sb => sb && sb.branch_id === lastSavedBranchId);
checkpoints.push({ passed: !!savedQualifying, weight: 0.30 });

// CP3 (0.35): Saved branch is one of the cheapest qualifying options and was saved from fee comparison
let cp3Passed = false;
if (lastSavedBranchId && cheapestAmount != null) {
  const savedSchedule = qualifyingSchedules.find(fs => fs.branch_id === lastSavedBranchId);
  if (savedSchedule && savedSchedule.amount === cheapestAmount) {
    const savedRecord = savedBranches.find(sb => sb && sb.branch_id === lastSavedBranchId);
    cp3Passed = !!savedRecord && savedRecord.source === 'fee_comparison';
  }
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const viewStates = JSON.parse(localStorage.getItem('branch_search_view_states') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const rvBranches = JSON.parse(localStorage.getItem('recently_viewed_branches') || '[]');
let clipboard = null;
try { clipboard = JSON.parse(localStorage.getItem('__clipboard__') || 'null'); } catch (e) { clipboard = null; }

const parseTimeToMinutes = (t) => {
  if (!t || typeof t !== 'string') return null;
  const parts = t.split(':');
  if (parts.length !== 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
};

// Candidate branches: Dubai Marina, Dubai, corporate banking, weekday close >= 20:00, with routing code
const candidateBranches = branches.filter(br => {
  if (!br || br.area !== 'Dubai Marina' || br.city !== 'Dubai') return false;
  const hasCorp = !!br.has_corporate_banking || (Array.isArray(br.service_types) && br.service_types.includes('corporate_banking'));
  if (!hasCorp) return false;
  const mins = parseTimeToMinutes(br.weekday_close_time);
  if (mins == null || mins < 20 * 60) return false;
  return typeof br.routing_code === 'string' && br.routing_code.length > 0;
});

// CP1 (0.35): Branch Locator filtered to Dubai Marina corporate branches with closing time after 8 PM
const locatorState = viewStates.find(vs => vs && vs.mode === 'branch_locator');
const cp1Passed = !!locatorState &&
  locatorState.area_filter === 'Dubai Marina' &&
  Array.isArray(locatorState.service_type_filters) && locatorState.service_type_filters.includes('corporate_banking') &&
  locatorState.closing_time_filter === 'after_8_pm';
checkpoints.push({ passed: cp1Passed, weight: 0.35 });

// CP2 (0.30): User opened at least one qualifying late-closing Dubai Marina corporate branch
const openedCandidateIds = rvBranches.filter(id => candidateBranches.some(br => br.id === id));
checkpoints.push({ passed: openedCandidateIds.length >= 1, weight: 0.30 });

// CP3 (0.35): Clipboard holds routing code of an opened qualifying branch
let cp3Passed = false;
if (clipboard && clipboard.value && openedCandidateIds.length > 0) {
  cp3Passed = candidateBranches.some(br =>
    openedCandidateIds.includes(br.id) && br.routing_code === clipboard.value
  );
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const ibanResults = JSON.parse(localStorage.getItem('iban_validation_results') || '[]');
const rvBranches = JSON.parse(localStorage.getItem('recently_viewed_branches') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const banks = JSON.parse(localStorage.getItem('banks') || '[]');
let clipboard = null;
try { clipboard = JSON.parse(localStorage.getItem('__clipboard__') || 'null'); } catch (e) { clipboard = null; }

const enbdBank = banks.find(b => b && b.name === 'Emirates NBD');
const expectedIbanNormalized = 'AE070331234567890123456';

const normalizeIban = (s) => (s || '').replace(/\s+/g, '').toUpperCase();

// Find the most recent validation result for the expected IBAN mapped to Emirates NBD
let matchingResults = ibanResults.filter(r => normalizeIban(r && r.input_iban) === expectedIbanNormalized);
const validationResult = matchingResults.length ? matchingResults[matchingResults.length - 1] : null;

// CP1 (0.30): IBAN validated and resolved to Emirates NBD as a valid result
const cp1Passed = !!validationResult && !!enbdBank &&
  validationResult.bank_id === enbdBank.id &&
  validationResult.validation_status === 'valid';
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Determine the target "first" Deira branch for Emirates NBD (by name ascending)
let targetBranch = null;
if (enbdBank) {
  const enbdDeiraBranches = branches
    .filter(br => br && br.bank_id === enbdBank.id && br.area === 'Deira')
    .slice()
    .sort((a, b) => (a.name || '').toLowerCase().localeCompare((b.name || '').toLowerCase()));
  if (enbdDeiraBranches.length) targetBranch = enbdDeiraBranches[0];
}

// CP2 (0.30): User opened the target Deira branch after validation
const cp2Passed = !!targetBranch && rvBranches.includes(targetBranch.id);
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// CP3 (0.40): Clipboard holds the primary SWIFT code of the target Deira branch
let cp3Passed = false;
if (targetBranch && clipboard && clipboard.value) {
  cp3Passed = targetBranch.swift_primary_code === clipboard.value;
}
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const viewStates = JSON.parse(localStorage.getItem('branch_search_view_states') || '[]');
const comparisonSets = JSON.parse(localStorage.getItem('branch_comparison_sets') || '[]');
const supports = JSON.parse(localStorage.getItem('branch_currency_supports') || '[]');
const savedBranches = JSON.parse(localStorage.getItem('saved_branches') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const banks = JSON.parse(localStorage.getItem('banks') || '[]');

// CP1 (0.30): Branch Locator filtered to Deira branches with USD in currency filters
const locatorState = viewStates.find(vs => vs && vs.mode === 'branch_locator');
const cp1Passed = !!locatorState &&
  locatorState.area_filter === 'Deira' &&
  Array.isArray(locatorState.currency_filters) && locatorState.currency_filters.includes('USD');
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// Build lookups
const bankById = {};
banks.forEach(b => { if (b && b.id) bankById[b.id] = b; });
const supportsByBranchId = {};
supports.forEach(s => {
  if (!s || !s.branch_id) return;
  if (!supportsByBranchId[s.branch_id]) supportsByBranchId[s.branch_id] = [];
  supportsByBranchId[s.branch_id].push(s);
});

const enbd = banks.find(b => b && b.name === 'Emirates NBD');
const mashreq = banks.find(b => b && b.name === 'Mashreq Bank');

const branchSupportsUsdIntl = (branchId) => {
  const arr = supportsByBranchId[branchId] || [];
  return arr.some(s => s.currency_code === 'USD' && s.supports_international_transfers);
};

// Candidate comparison branches: Deira, USD-supporting, one from Emirates NBD and one from Mashreq
const enbdCandidates = enbd ? branches.filter(br => br && br.bank_id === enbd.id && br.area === 'Deira' && branchSupportsUsdIntl(br.id)) : [];
const mashreqCandidates = mashreq ? branches.filter(br => br && br.bank_id === mashreq.id && br.area === 'Deira' && branchSupportsUsdIntl(br.id)) : [];

const activeSet = comparisonSets.length ? comparisonSets[comparisonSets.length - 1] : null;
const setBranchIds = activeSet && Array.isArray(activeSet.branch_ids) ? activeSet.branch_ids : [];

const hasEnbdInSet = enbdCandidates.some(br => setBranchIds.includes(br.id));
const hasMashreqInSet = mashreqCandidates.some(br => setBranchIds.includes(br.id));

// CP2 (0.30): Comparison set includes at least one qualifying Deira USD branch from each of Emirates NBD and Mashreq
const cp2Passed = !!activeSet && hasEnbdInSet && hasMashreqInSet;
checkpoints.push({ passed: cp2Passed, weight: 0.30 });

// Determine which compared branch has the earlier USD transfer cut-off time
const parseTimeToMinutes = (t) => {
  if (!t || typeof t !== 'string') return null;
  const parts = t.split(':');
  if (parts.length !== 2) return null;
  const h = parseInt(parts[0], 10);
  const m = parseInt(parts[1], 10);
  if (isNaN(h) || isNaN(m)) return null;
  return h * 60 + m;
};

const enbdInSet = enbdCandidates.filter(br => setBranchIds.includes(br.id));
const mashreqInSet = mashreqCandidates.filter(br => setBranchIds.includes(br.id));

const candidateCompared = enbdInSet.concat(mashreqInSet);

let earliestBranchId = null;
let earliestMinutes = null;

candidateCompared.forEach(br => {
  const arr = supportsByBranchId[br.id] || [];
  const usdSupport = arr.find(s => s.currency_code === 'USD' && s.supports_international_transfers && typeof s.transfer_cutoff_time === 'string');
  if (!usdSupport) return;
  const mins = parseTimeToMinutes(usdSupport.transfer_cutoff_time);
  if (mins == null) return;
  if (earliestMinutes == null || mins < earliestMinutes) {
    earliestMinutes = mins;
    earliestBranchId = br.id;
  }
});

// CP3 (0.40): User saved from comparison the branch with the earliest USD cut-off
let cp3Passed = false;
if (earliestBranchId) {
  const saved = savedBranches.find(sb => sb && sb.branch_id === earliestBranchId && sb.source === 'branch_comparison');
  cp3Passed = !!saved;
}
checkpoints.push({ passed: cp3Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const viewStates = JSON.parse(localStorage.getItem('branch_search_view_states') || '[]');
const comparisonSets = JSON.parse(localStorage.getItem('branch_comparison_sets') || '[]');
const supports = JSON.parse(localStorage.getItem('branch_currency_supports') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');
const banks = JSON.parse(localStorage.getItem('banks') || '[]');

// CP1 (0.40): Branch Locator filtered to First Abu Dhabi Bank, city Dubai, with EUR and USD in currency filters
const fabBank = banks.find(b => b && b.name === 'First Abu Dhabi Bank');
const locatorState = viewStates.find(vs => vs && vs.mode === 'branch_locator');
const cp1Passed = !!locatorState && !!fabBank &&
  locatorState.bank_name_filter === 'First Abu Dhabi Bank' &&
  locatorState.city_filter === 'Dubai' &&
  Array.isArray(locatorState.currency_filters) &&
  locatorState.currency_filters.includes('USD') &&
  locatorState.currency_filters.includes('EUR');
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// Build supports lookup
const supportsByBranchId = {};
supports.forEach(s => {
  if (!s || !s.branch_id) return;
  if (!supportsByBranchId[s.branch_id]) supportsByBranchId[s.branch_id] = [];
  supportsByBranchId[s.branch_id].push(s);
});

const supportsBothEurUsdIntl = (branchId) => {
  const arr = supportsByBranchId[branchId] || [];
  const hasUsd = arr.some(s => s.currency_code === 'USD' && s.supports_international_transfers);
  const hasEur = arr.some(s => s.currency_code === 'EUR' && s.supports_international_transfers);
  return hasUsd && hasEur;
};

// Qualifying FAB Dubai branches supporting both EUR and USD international transfers
const fabBranches = fabBank ? branches.filter(br => br && br.bank_id === fabBank.id && br.city === 'Dubai') : [];
const qualifyingFabBranches = fabBranches.filter(br => supportsBothEurUsdIntl(br.id));
const qualifyingIds = qualifyingFabBranches.map(br => br.id);

const activeSet = comparisonSets.length ? comparisonSets[comparisonSets.length - 1] : null;
const setBranchIds = activeSet && Array.isArray(activeSet.branch_ids) ? activeSet.branch_ids : [];

const inSetQualifyingIds = qualifyingIds.filter(id => setBranchIds.includes(id));

// CP2 (0.60): At least two qualifying FAB Dubai branches (supporting EUR & USD intl) are in the comparison set
const cp2Passed = !!activeSet && inSetQualifyingIds.length >= 2;
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checklists = [];
const checkpoints = checklists; // alias for consistency

const guides = JSON.parse(localStorage.getItem('guides') || '[]');
const rvGuides = JSON.parse(localStorage.getItem('recently_viewed_guides') || '[]');
const savedGuides = JSON.parse(localStorage.getItem('saved_guides') || '[]');

// Qualifying guides: tagged 'IBAN basics', reading time <= 10, and focused on Dubai IBAN structure
const qualifyingGuides = guides.filter(g => {
  if (!g) return false;
  const hasTag = Array.isArray(g.tags) && g.tags.includes('IBAN basics');
  const withinTime = typeof g.estimated_reading_time_minutes === 'number' && g.estimated_reading_time_minutes <= 10;
  const title = (g.title || '').toLowerCase();
  const desc = (g.short_description || '').toLowerCase();
  const topicMatch = title.includes('dubai iban') || desc.includes('dubai iban') ||
    title.includes('iban structure') || desc.includes('iban structure');
  return hasTag && withinTime && topicMatch;
});

const qualifyingIds = qualifyingGuides.map(g => g.id);

// CP1 (0.40): User opened at least one qualifying Dubai IBAN structure guide
const cp1Passed = rvGuides.some(id => qualifyingIds.includes(id));
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): User bookmarked at least one qualifying guide into the reading list
const cp2Passed = savedGuides.some(bg => bg && qualifyingIds.includes(bg.guide_id) && bg.is_in_reading_list === true);
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reports = JSON.parse(localStorage.getItem('branch_issue_reports') || '[]');
const branches = JSON.parse(localStorage.getItem('branches') || '[]');

// Candidate branches: located in Jumeirah, offering both retail and corporate banking
const candidateBranches = branches.filter(br => {
  if (!br || br.area !== 'Jumeirah') return false;
  const hasRetail = !!br.has_retail_banking || (Array.isArray(br.service_types) && br.service_types.includes('retail_banking'));
  const hasCorp = !!br.has_corporate_banking || (Array.isArray(br.service_types) && br.service_types.includes('corporate_banking'));
  return hasRetail && hasCorp;
});

const candidateIds = candidateBranches.map(br => br.id);

const reportsForCandidates = reports.filter(r => r && candidateIds.includes(r.branch_id));

// CP1 (0.50): Issue report submitted for a qualifying Jumeirah branch with type 'incorrect_branch_code'
const cp1Passed = reportsForCandidates.some(r => r.issue_type === 'incorrect_branch_code');
checkpoints.push({ passed: cp1Passed, weight: 0.50 });

// CP2 (0.50): Among those, at least one report has medium urgency and send_copy_to_reporter = true
const cp2Passed = reportsForCandidates.some(r =>
  r.issue_type === 'incorrect_branch_code' &&
  r.urgency === 'medium' &&
  r.send_copy_to_reporter === true
);
checkpoints.push({ passed: cp2Passed, weight: 0.50 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
